// How Make queries the Kernel filesystem physically (Simplified):
#include <sys/stat.h>

struct stat src_stat, obj_stat;
stat("main.c", &src_stat); // Query Kernel for Source metadata
stat("main.o", &obj_stat); // Query Kernel for Object metadata

if (src_stat.st_mtime > obj_stat.st_mtime) {
    execute_compiler(); // main.c is newer. Rebuild!
}
